// services/geminiService.ts

import { FilterCriteria } from "../types";
import { googleSearch } from "./googleSearchService";

export const findDoctors = async (
  latitude: number | null,
  longitude: number | null,
  filters: FilterCriteria
) => {
  const queryParts = ['Using Google Search, find top-rated doctors.'];
  const filterDetails = [];

  if (filters.doctorName) filterDetails.push(`the doctor's name must be "${filters.doctorName}" `);
  if (filters.hospitalName) filterDetails.push(`the hospital name must be "${filters.hospitalName}" `);
  if (filters.specialty) filterDetails.push(`their specialty must be "${filters.specialty }"`);

  let locationContext = '';
  if (filters.location) {
    locationContext = `in or near ${filters.location}`;
  } else if (latitude && longitude) {
    locationContext = `near latitude ${latitude} and longitude ${longitude}`;
  }

  if (locationContext) {
      queryParts.push(locationContext);
  }

  if (filterDetails.length > 0) {
       queryParts.push(`Apply the following filters: ${filterDetails.join(', ')}.`);
  }

  if (filters.availableNow) {
    queryParts.push(`Only include doctors who are available for consultation right now.`);
   }

  queryParts.push('Rank results by prioritizing doctors with high ratings and a significant number of reviews.'); 
  queryParts.push('For each doctor found, you must provide their full name, specialty, complete address, hospital affiliation, a contact phone number for booking appointments, and their rating.');
  queryParts.push('Your final output must be a single, clean JSON object with one key: "doctors". The value should be an array of the doctor objects you found. Do not include any other text, explanations, or markdown formatting in your response.');

  const prompt = queryParts.join(' ');
  const result = await googleSearch(prompt);
  const doctors = JSON.parse(result) as { doctors: any[] };

  return doctors;
};
